import json
import requests

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    enrich_url_header = 'x-enrich-url'
    if enrich_url_header in headers:
        enrich_url = headers[enrich_url_header][0]['value']
        
        try:
            response = requests.get(enrich_url, timeout=2)
            if response.status_code == 200:
                enrich_data = response.json()
                request['headers']['x-enrich-data'] = [{
                    'key': 'X-Enrich-Data',
                    'value': json.dumps(enrich_data)
                }]
        except requests.RequestException as e:
            print(f"Error fetching enrichment data: {e}")
    
    return request